import React, { useState, useMemo } from 'react';
import Sidebar from './components/layout/Sidebar';
import Header from './components/layout/Header';
import CommandCenter from './pages/CommandCenter';
import Parameters from './pages/Parameters';
import FileUploader from './components/FileUploader';
import { processCombinedData } from './utils/dataProcessor';

function App() {
  const [dataFiles, setDataFiles] = useState(null);
  const [activeTab, setActiveTab] = useState('command');
  const [config, setConfig] = useState({ proyectado: 239000 });

  // 1. Nueva bandera para forzar el re-upload sin perder el estado de App
  const [isUploading, setIsUploading] = useState(false);

  const dashboardData = useMemo(() => {
    if (!dataFiles) return null;
    console.log("Recalculando con proyectado:", config.proyectado);
    return processCombinedData(dataFiles.csv, dataFiles.excel, config.proyectado);
  }, [dataFiles, config.proyectado]);

  // 2. Función para manejar la carga (nueva o actualización)
  const handleDataLoad = (csv, excel) => {
    setDataFiles({ csv, excel });
    setIsUploading(false); // Cerramos el uploader al terminar
    setActiveTab('command'); // Volvemos al monitor automáticamente
  };

  // 3. Lógica de renderizado: Mostramos uploader si no hay datos O si el usuario pide "New Dispatch"
  if (!dataFiles || isUploading) {
    return (
      <FileUploader 
        onAllDataLoaded={handleDataLoad} 
        // Pasamos una opción para cancelar solo si ya hay datos previos
        onCancel={dataFiles ? () => setIsUploading(false) : null}
      />
    );
  }

  return (
    <div className="flex h-screen bg-[#080c14] text-slate-300 overflow-hidden font-sans">
      {/* 4. Le pasamos al Sidebar la función para activar el re-upload */}
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        onNewDispatch={() => setIsUploading(true)} 
      />

      <main className="flex-1 flex flex-col overflow-y-auto">
        <Header title={activeTab === 'command' ? "OCASA COMMAND CENTER" : "AJUSTE DE PARÁMETROS"} />

        <div className="p-10">
          {activeTab === 'command' ? (
            <CommandCenter data={dashboardData} />
          ) : (
            <Parameters config={config} setConfig={setConfig} />
          )}
        </div>
      </main>
    </div>
  );
}

export default App;
